// Recupera o item de entrada do nó anterior
const input = $('Valida playload').first().json;
const url = input.data.url_image;

if (!url) {
  return { error: "URL não fornecida" };
}

// --------------------------------------------------
// Gera FILE_PREFIX único (timestamp + id se existir)
// --------------------------------------------------

// Timestamp no formato yyyyMMddHHmmssSSS
const now = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp =
  now.getFullYear() +
  pad(now.getMonth() + 1, 2) +
  pad(now.getDate(), 2) +
  pad(now.getHours(), 2) +
  pad(now.getMinutes(), 2) +
  pad(now.getSeconds(), 2) +
  pad(now.getMilliseconds(), 3);

// Se tiver um ID no fluxo, usa. Se não, coloca "noid"
const id = input.id || "noid";

// Prefixo final
const FILE_PREFIX = `${timestamp}_${id}`;

// --------------------------------------------------
// Detecta extensão do arquivo (versão segura)
// --------------------------------------------------

const cleanUrl = url.split('?')[0].toLowerCase();

let extension = null;

if (cleanUrl.includes('.pdf')) {
  extension = 'pdf';
} 
else if (
  cleanUrl.includes('.jpg') ||
  cleanUrl.includes('.jpeg') ||
  cleanUrl.includes('.png') ||
  cleanUrl.includes('.webp') ||
  cleanUrl.includes('.bmp')
) {
  extension = 'img';
}

let result = {};

if (extension === 'img') {
  result = {
    extension: "img",
    url_final: url
  };
} else if (extension === 'pdf') {
  result = {
    extension: "pdf",
    url_final: url
  };
} else {
  result = {
    extension: "unknown"
  };
}
// Retorna o resultado mantendo o ID original para referência no fluxo
return {
  ...result,
  FILE_PREFIX
};

// Captura os dados do item atual que chegou ao nó
const currentItem = $input.first().json;

let urlFinal = null;

try {
  // 1. Tenta buscar do caminho do PDF (Upload a file1)
  // Usamos o optional chaining (?.) para não travar se o nó não existir
  const uploadNode = $("API PDF Converter")?.item?.json;
  if (uploadNode && uploadNode.conversionUrl) {
    urlFinal = uploadNode.conversionUrl;
  }
} catch (e) {
  // Nó não executado, apenas ignora o erro
}

if (!urlFinal) {
  try {
    // 2. Tenta buscar do caminho da Imagem (Switch / identifica a extensao)
    const switchNode = $("Switch")?.item?.json;
    if (switchNode && switchNode.url_final) {
      urlFinal = switchNode.url_final;
    }
  } catch (e) {
    // Nó não executado, apenas ignora
  }
}

// Retorna um único objeto com a URL consolidada
return {
  url_consolidada: urlFinal,
  ...currentItem
};

const CAMPOS_PERMITIDOS = ["url_image", "user_medical_info_id"];

return $input.all().map((item) => {

  let body = item.json.body ?? item.json;

  // ================================
  // 1. Se vier como string, parseia
  // ================================
  if (typeof body === "string") {
    body = body.trim().replace(/}}+$/, "}");

    try {
      body = JSON.parse(body);
    } catch (e) {
      return {
        json: {
          success: false,
          status: 400,
          error: {
            code: "INVALID_JSON",
            message: "Body não é um JSON válido",
            received: body
          }
        }
      };
    }
  }

  // ==========================================
  // 2. Sanitiza valores string (multipart bug)
  // ==========================================
  for (const key in body) {
    if (typeof body[key] === "string") {
      body[key] = body[key].trim().replace(/}}+$/, "");
    }
  }

  // ================================
  // 3. Campos desconhecidos
  // ================================
  const camposEnviados = Object.keys(body);
  const camposInvalidos = camposEnviados.filter(
    (c) => !CAMPOS_PERMITIDOS.includes(c)
  );

  if (camposInvalidos.length > 0) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "INVALID_FIELD",
          message: "Campo(s) não reconhecido(s) no payload",
          invalid_fields: camposInvalidos,
          allowed_fields: CAMPOS_PERMITIDOS
        }
      }
    };
  }

  // ================================
  // 4. url_image obrigatório
  // ================================
  if (!body.url_image) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "MISSING_FIELD",
          message: "O campo 'url_image' é obrigatório",
          example: {
            url_image: "https://site.com/image.png",
            user_medical_info_id: 123
          }
        }
      }
    };
  }

  // ================================
  // 5. user_medical_info_id obrigatório
  // ================================
  if (body.user_medical_info_id === undefined) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "MISSING_FIELD",
          message: "O campo 'user_medical_info_id' é obrigatório"
        }
      }
    };
  }

  // ================================
  // 6. Tipagem do ID
  // ================================
  const id = body.user_medical_info_id;

  if (
    !(
      typeof id === "number" ||
      (typeof id === "string" && /^\d+$/.test(id))
    )
  ) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "INVALID_TYPE",
          message: "'user_medical_info_id' deve ser número ou string numérica",
          received: id
        }
      }
    };
  }

  // ================================
  // ✅ SUCESSO
  // ================================
  return {
    json: {
      success: true,
      status: 200,
      data: {
        url_image: body.url_image,
        user_medical_info_id: Number(id)
      }
    }
  };
});

/**
 * CLIENT-SPECIFIC SCORING — Simple Validator (Standalone)
 * Minimal conceptual alignment fixes:
 * 1) Requirement: OU (carimbo + assinatura) OU (QR Code validado).
 * 2) "Assinatura Digital" check should NOT be treated as inconsistency when physical path (carimbo+assinatura) is valid.
 * 3) Same weight for both paths (OR gate) applied in scoring.
 * 4) Remove double counting: QR/carimbo issues no longer hard-fail dataConsistency.
 * 5) Score always clamped 0..100.
 *
 * PATCH v2:
 * 6) Patient vs employee name cross-check now consumed from employe_data.
 * 7) decision.status / rationale from upstream node now consumed.
 * 8) patientEmployeeNameMatch === false is a hardFail in dataConsistency.
 * 9) upstreamForcesManualReview adds softWarn and guarantees score >= 50.
 * 10) decisionRationale lines surfaced as danger bullets in groupsHIGH.
 *
 * PATCH v3:
 * 11) groupsHIGH rewritten to use real data — no more hardcoded negative bullets.
 *     HIGH groups show the same factual state as LOW/MEDIUM, with:
 *     - danger emphasis on confirmed problems (name mismatch, auth failure)
 *     - decisionRationale lines as explicit danger bullets
 *     - CRM/QR/stamp shown accurately based on actual values
 *
 * n8n input source:
 *   const raw = $('API SADM').first().json.inputRaw;
 */

// ---------------- helpers ----------------
function get(obj, path, fallback = null) {
  try {
    const parts = path.split(".");
    let cur = obj;
    for (const p of parts) {
      if (cur == null) return fallback;
      cur = cur[p];
    }
    return cur === undefined ? fallback : cur;
  } catch {
    return fallback;
  }
}

function clamp(n, a, b) {
  const x = Number.isFinite(n) ? n : 0;
  return Math.max(a, Math.min(b, x));
}

function isTrue(v) { return v === true; }

function pickCrmUF(input) {
  return (
    get(input, "medical_professional.cfm_data.cfm_data.crm_state", "") ||
    get(input, "medical_professional.crm_state", "") ||
    ""
  );
}

function authenticationMethodText() {
  if (stpSt === "PASS" && qrIsValid) {
    return "Documento autenticado por QR Code e carimbo com assinatura.";
  }

  if (stpSt === "PASS") {
    return "Documento autenticado por carimbo e assinatura.";
  }

  if (qrIsValid) {
    return "Documento autenticado por QR Code válido.";
  }

  if (stpSt === "WARN") {
    return "Carimbo ou assinatura presentes, porém com baixa legibilidade.";
  }

  return "Nenhum método de autenticação válido identificado.";
}

// ---------------- input normalization ----------------
// PRESERVED: referências originais do fluxo API SADM
const raw = $('API SADM').first().json.inputRaw;
const input = Array.isArray(raw) ? (raw[0] ?? {}) : (raw ?? {});

const webhookId =
  $('Webhook').first().json.body?.user_medical_info_id ?? null;

const userMedicalInfoId =
  webhookId ??
  get(input, "user_medical_info_id", null) ??
  get(input, "document_metadata.user_medical_info_id", null) ??
  null;

// PATCH v2: dados_manuais — lidos do Webhook (equivalente ao Start do outro fluxo)
const dadosManuais = $('Webhook').first().json.body?.dados_manuais || {};
const temDadosManuais = Object.keys(dadosManuais).length > 0;

const docType = get(input, "document_metadata.document_type", "");
const isMedCert = isTrue(get(input, "document_metadata.is_medical_certificate", false));

const ocrConf = Number(get(input, "ocr.confidence_avg", 0));
const matchScore = Number(get(input, "ocr.match_score", 0));
const mismatchFields = get(input, "ocr.mismatch_fields", []);
const ocrHasMismatch = Array.isArray(mismatchFields) && mismatchFields.length > 0;

const patientName = get(input, "patient_identification.patient_name", "");

const cid = get(input, "medical_classification.cid_parent", "");
const cidFound = get(input, "medical_classification.cid_oms_data.cid_found", null);

const leaveDays = Number(get(input, "attendance_information.leave.days", 0));
const leaveRisk = get(input, "attendance_information.leave.leave_days_risk", "");

const attendanceDateStatus = get(input, "attendance_information.attendance_date_status", "");
const captureType = get(input, "capture.capture_type", "");

const crmNumber = get(input, "medical_professional.crm_number", "");
const crmUF = pickCrmUF(input);
const crmSituation = get(input, "medical_professional.cfm_data.cfm_data.situation", "");
const crmMatchStatus = get(input, "medical_professional.cfm_data.cfm_data.match_status", "");
const crmMatchScore = Number(get(input, "medical_professional.cfm_data.cfm_data.match_score", 0));

const hasStamp = isTrue(get(input, "document_elements.has_stamp", false));
const stampValid = isTrue(get(input, "document_elements.stamp_valid", false));

// IMPORTANT: "carimbo com assinatura" requires BOTH stamp + handwritten signature
const hasHandSignature = isTrue(get(input, "document_elements.has_signature", false));
const handSignatureValid = isTrue(get(input, "document_elements.signature_valid", false));

const hasMandatoryFields = isTrue(get(input, "document_elements.has_mandatory_fields", false));
const hasDoctorData = isTrue(get(input, "document_elements.has_doctor_data", false));
const hasPatientData = isTrue(get(input, "document_elements.has_patient_data", false));
const hasAttendanceData = isTrue(get(input, "document_elements.has_attendance_data", false));

const manipulationDetected = isTrue(get(input, "manipulation_analysis.detected", false));
const digitalManip = get(input, "forensic_analysis.digital_manipulation_indicators", "none");
const physicalManip = get(input, "forensic_analysis.physical_manipulation_indicators", "none");
const aiIndicators = get(input, "forensic_analysis.ai_generation_or_reconstruction_indicators", "none");
const anyVisualIssue = (() => {
  const vq = get(input, "forensic_analysis.visual_quality_issues", {});
  if (!vq || typeof vq !== "object") return false;
  return Object.values(vq).some(x => x === true);
})();

const imgConsistency = Number(get(input, "image_scores.consistency", 1));
const imgCompleteness = Number(get(input, "image_scores.completeness", 1));
const imgQuality = Number(get(input, "image_scores.image_quality", 1));

// QR (client uses as "Assinatura Digital")
const qrExists = isTrue(get(input, "qr_validation.qr_code_data.qr_exists", false));
const qrDecodable = isTrue(get(input, "qr_validation.qr_code_data.qr_decodable", false));
const qrUrlStatus = get(input, "qr_validation.qr_code_data.qr_url_status", "");
const qrIsValid = (qrExists && qrDecodable && qrUrlStatus === "active");

// ---------------- PATCH v2: patient vs employee cross-check ----------------
const employeData = get(input, "patient_identification.employe_data", {});
const patientEmployeeNameMatch = get(employeData, "patient_employee_name_match", null);
const patientEmployeeNameScore = Number(get(employeData, "patient_employee_name_score", -1));
const allDocumentsMatch = get(employeData, "all_documents_match", null);

// ---------------- PATCH v2: upstream decision ----------------
// PRESERVED: lido do input (não há startNode neste fluxo; fallback para input apenas)
const decisionStatus = get(input, "decision.status", "");
const decisionRationale = (() => {
  const r = get(input, "decision.rationale", null);
  return Array.isArray(r) ? r : [];
})();
const upstreamForcesManualReview = (
  decisionStatus === "manual_verification_required" ||
  decisionStatus === "rejected"
);

// ---------------- check status mapping (client) ----------------

function stampStatus() {
  if (!hasStamp) return "FAIL";
  if (hasStamp && stampValid && hasHandSignature && handSignatureValid) return "PASS";
  return "WARN";
}

function signatureStatus(stpSt) {
  if (stpSt === "PASS") return "PASS";
  if (!qrExists) return "FAIL";
  if (qrIsValid) return "PASS";
  return "FAIL";
}

function sealOrQrStatus(sigSt, stpSt) {
  if (sigSt === "PASS" || stpSt === "PASS") return "PASS";
  if (sigSt === "WARN" || stpSt === "WARN") return "WARN";
  return "FAIL";
}

function dataConsistencyStatus(sealOrQrSt) {
  const crmOk = (String(crmSituation).toLowerCase() === "active") && (String(crmMatchStatus).toLowerCase() === "matched");
  const cidOk = (cid !== "" && cidFound === true);
  const imgOk = (imgConsistency >= 0.9 && imgCompleteness >= 0.9 && imgQuality >= 0.9);
  const ocrOk = (ocrConf >= 0.95 && !ocrHasMismatch && matchScore >= 0.95);
  const temporalOk = (attendanceDateStatus === "within_deadline" || attendanceDateStatus === "" || attendanceDateStatus === "unknown");

  const hardFail =
    manipulationDetected ||
    digitalManip === "strong" || physicalManip === "strong" ||
    aiIndicators === "confirmed" || aiIndicators === "likely" ||
    !hasMandatoryFields ||
    !hasDoctorData || !hasPatientData || !hasAttendanceData ||
    patientEmployeeNameMatch === false; // PATCH v2

  if (hardFail) return "FAIL";

  const softWarn =
    (sealOrQrSt !== "PASS") ||
    !crmOk ||
    !cidOk ||
    !imgOk ||
    !ocrOk ||
    !temporalOk ||
    (leaveDays >= 10) ||
    (String(leaveRisk).toLowerCase() === "high" || String(leaveRisk).toLowerCase() === "very_high") ||
    (captureType === "scan") ||
    anyVisualIssue ||
    (digitalManip !== "none" || physicalManip !== "none" || aiIndicators !== "none") ||
    upstreamForcesManualReview; // PATCH v2

  if (softWarn) return "WARN";
  return "PASS";
}

// ---------------- compute statuses (ORDER MATTERS) ----------------
const stpSt = stampStatus();
const sigSt = signatureStatus(stpSt);
const sealQrSt = sealOrQrStatus(sigSt, stpSt);
const datSt = dataConsistencyStatus(sealQrSt);

// Se tiver dados preenchidos manualmente então datSt é warn
let datStFinal = datSt;
if (temDadosManuais && datSt === "PASS") {
  datStFinal = "WARN";
}

// ---------------- scoring (0..100) ----------------
let score = 9;

if (!isMedCert || docType !== "medical_certificate") score += 85;

if (sealQrSt === "FAIL") score += 40;
if (sealQrSt === "WARN") score += 18;

if (datStFinal === "FAIL") score += 45;
if (datStFinal === "WARN") score += 20;

if (String(crmSituation).toLowerCase() !== "active") score += 30;
if (String(crmMatchStatus).toLowerCase() !== "matched") score += 20;
if (Number.isFinite(crmMatchScore) && crmMatchScore > 0 && crmMatchScore < 0.35) score += 10;

if (cid === "") score += 10;
if (cidFound === false) score += 25;

if (ocrConf > 0 && ocrConf < 0.90) score += 18;
else if (ocrConf > 0 && ocrConf < 0.95) score += 8;

if (ocrHasMismatch) score += 12;

if (leaveDays >= 15) score += 18;
else if (leaveDays >= 10) score += 12;
else if (leaveDays >= 6) score += 6;

if (manipulationDetected) score += 35;
if (digitalManip !== "none") score += (digitalManip === "weak" ? 8 : digitalManip === "moderate" ? 18 : 28);
if (physicalManip !== "none") score += (physicalManip === "weak" ? 6 : physicalManip === "moderate" ? 14 : 22);
if (aiIndicators !== "none") score += (aiIndicators === "suspected" ? 12 : aiIndicators === "likely" ? 22 : 30);

if (anyVisualIssue) score += 10;

// Penalidade por dados preenchidos manualmente
if (temDadosManuais) {
  const qtd = Object.keys(dadosManuais).length;
  if (qtd <= 2) score += 8;
  else if (qtd <= 4) score += 15;
  else score += 25;
}

// PATCH v2: patient vs employee name mismatch
if (patientEmployeeNameMatch === false) {
  score += 45;
} else if (patientEmployeeNameScore >= 0 && patientEmployeeNameScore < 0.70) {
  score += 20;
}

// PATCH v2: document cross-check failures
if (allDocumentsMatch === false) score += 15;

score = clamp(Math.round(score), 0, 100);

// PATCH v2: upstream decision override
if (upstreamForcesManualReview) {
  score = Math.max(score, 50);
}

score = clamp(Math.round(score), 0, 100);

// ---------------- risk level bands (client UI) ----------------
const riskLevel =
  score >= 80 ? "HIGH" :
  score >= 50 ? "MEDIUM" :
  "LOW";

// ---------------- copy-safe text builders (deterministic) ----------------
function buildHeadline(risk) {
  if (risk === "HIGH") return "Possível fraude detectada pela IA";
  return "Verificação manual recomendada";
}

function buildSummary(risk) {
  if (risk === "HIGH") return "Inconsistências significativas nos dados do documento.";
  return "Documento validado com atenção. Alguns detalhes requerem verificação manual.";
}

function buildTags(risk, scoreValue, checksArr) {
  if (risk === "LOW") return ["Baixo Risco"];
  if (risk === "MEDIUM") {
    const att = checksArr.filter(c => c.status !== "PASS").length;
    return [`Risco Moderado`, `${att} pontos de atenção`];
  }
  const probs = checksArr.filter(c => c.status === "FAIL").length + (scoreValue >= 90 ? 2 : 0);
  return ["Risco Alto", `${Math.max(1, probs)} problemas graves`];
}

// ---------------- shared bullet helpers ----------------

function dadosManuaisBullet() {
  if (!temDadosManuais) return [];
  return [{
    text: `Dados ajustados manualmente → ${
      Object.entries(dadosManuais)
        .map(([k, v]) => {
          const labels = {
            data_inicio: "Data início",
            data_fim: "Data fim",
            dias_consecutivos: "Dias",
            nome_medico: "Médico",
            crm: "CRM",
            cid: "CID"
          };
          return `${labels[k] || k}: ${v}`;
        })
        .join(" | ")
    }`,
    emphasis: "danger"
  }];
}

// ---------------- groups ----------------

function groupsLOW() {
  return [
    {
      title: "1. Consistência de Dados",
      bullets: [
        { text: patientName ? "Nome do paciente presente no documento" : "Nome do paciente ausente ou incompleto", emphasis: null },
        { text: "Datas em formato padrão brasileiro (dd/mm/aaaa)", emphasis: null },
        { text: cid ? `CID ${cid} informado` : "CID não informado", emphasis: null },
        ...dadosManuaisBullet()
      ],
    },
    {
      title: "2. Formatação Profissional",
      bullets: [
        { text: "Documento segue padrões médicos convencionais", emphasis: null },
        { text: "Formatação adequada e organizada", emphasis: null },
        { text: isTrue(get(input, "document_elements.has_letterhead", false)) ? "Presença de papel timbrado identificada" : "Papel timbrado não identificado", emphasis: null },
      ],
    },
    {
      title: "3. Informações Médicas",
      bullets: [
        { text: cid && cidFound === true ? `CID ${cid} compatível com o diagnóstico informado` : "CID não confirmado em base de referência", emphasis: null },
        { text: leaveDays > 0 ? `Período de afastamento: ${leaveDays} dia(s)` : "Sem afastamento informado", emphasis: null },
        { text: "Informações médicas completas e coerentes", emphasis: null },
      ],
    },
    {
      title: "4. Dados do Médico",
      bullets: [
        { text: crmNumber ? `CRM ${crmNumber}${crmUF ? `/${crmUF}` : ""} verificado e ativo` : "CRM ausente no documento", emphasis: null },
        { text: "Registro regular no Conselho Regional", emphasis: null },
       {
          text: authenticationMethodText(),
          emphasis: sealQrSt === "FAIL" ? "danger" : null
        },
      ],
    },
    {
      title: "5. Elementos de Segurança",
      bullets: [
        {
          text: stpSt === "PASS"
            ? authenticationMethodText()
            : (
                stpSt === "WARN"
                  ? "Carimbo/assinatura com legibilidade reduzida"
                  : "Carimbo/assinatura não identificados"
              ),
          emphasis: null
        },
        { text: "Qualidade de imagem adequada", emphasis: null },
        { text: "Sem sinais de adulteração digital", emphasis: null },
      ],
    },
  ];
}

function groupsMEDIUM() {
  return [
    {
      title: "1. Período de afastamento",
      bullets: [
        { text: `Duração de ${leaveDays || 0} dia(s) está acima da média`, emphasis: null },
        { text: cid ? `Para CID ${cid}, recomenda-se validar a coerência clínica do afastamento` : "Recomenda-se validar o CID informado", emphasis: null },
        { text: "Recomenda-se verificar histórico de atestados do colaborador", emphasis: null },
      ],
    },
    {
      title: "2. Qualidade da imagem",
      bullets: [
        { text: "Resolução abaixo do ideal em algumas áreas", emphasis: null },
        { text: stpSt === "WARN" ? "Carimbo/assinatura com legibilidade reduzida" : "Recomenda-se atenção aos elementos visuais de autenticação", emphasis: null },
        { text: "Recomenda-se solicitar cópia em melhor qualidade", emphasis: null },
      ],
    },
    {
      title: "3. Dados do Médico",
      bullets: [
        { text: crmNumber ? `CRM ${crmNumber}${crmUF ? `/${crmUF}` : ""} verificado e ativo` : "CRM não confirmado", emphasis: null },
        { text: "Registro em situação regular", emphasis: null },
        {
          text: authenticationMethodText(),
          emphasis: sealQrSt === "FAIL" ? "danger" : null
        },
      ],
    },
    {
      title: "4. Consistência de Dados",
      bullets: [
        { text: "Informações do paciente coerentes", emphasis: null },
        { text: "Datas em formato adequado", emphasis: null },
        { text: "Sem inconsistências críticas detectadas", emphasis: null },
        ...dadosManuaisBullet()
      ],
    },
  ];
}

// PATCH v3: groupsHIGH rewritten — all bullets driven by real data.
function groupsHIGH() {
  const crmOk = (String(crmSituation).toLowerCase() === "active") && (String(crmMatchStatus).toLowerCase() === "matched");

  return [
    {
      title: "1. Inconsistências de Dados",
      bullets: [
        {
          text: patientEmployeeNameMatch === false
            ? `Nome no documento (${patientName || "ausente"}) não corresponde ao funcionário cadastrado`
            : patientName
              ? `Paciente: "${patientName}"`
              : "Nome do paciente ausente",
          emphasis: patientEmployeeNameMatch === false ? "danger" : null
        },
        { text: cid ? `CID informado: ${cid}` : "CID não informado", emphasis: null },
        ...decisionRationale.map(r => ({ text: r, emphasis: "danger" })),
        ...dadosManuaisBullet()
      ],
    },
    {
      title: "2. Autenticação do Documento",
      bullets: [
        {
  title: "2. Autenticação do Documento",
  bullets: [
            {
              text: authenticationMethodText(),
