// PATCH v3: groupsHIGH rewritten — all bullets driven by real data.
function groupsHIGH() {
  const crmOk = (String(crmSituation).toLowerCase() === "active") && (String(crmMatchStatus).toLowerCase() === "matched");

  return [
    {
      title: "1. Inconsistências de Dados",
      bullets: [
        {
          text: patientEmployeeNameMatch === false
            ? `Nome no documento (${patientName || "ausente"}) não corresponde ao funcionário cadastrado`
            : patientName
              ? `Paciente: "${patientName}"`
              : "Nome do paciente ausente",
          emphasis: patientEmployeeNameMatch === false ? "danger" : null
        },
        { text: cid ? `CID informado: ${cid}` : "CID não informado", emphasis: null },
        ...decisionRationale.map(r => ({ text: r, emphasis: "danger" })),
        ...dadosManuaisBullet()
      ],
    },
    {
      title: "2. Autenticação do Documento",
      bullets: [
        {
  title: "2. Autenticação do Documento",
  bullets: [
            {
              text: authenticationMethodText(),
              emphasis: sealQrSt === "FAIL" ? "danger" : null
            }
          ],
        },
      ],
    },
    {
      title: "3. Informações Médicas",
      bullets: [
        {
          text: cid && cidFound === true
            ? `CID ${cid} compatível com o diagnóstico informado`
            : cid
              ? `CID ${cid}: requer validação de coerência clínica`
              : "CID não informado",
          emphasis: (!cid || cidFound === false) ? "danger" : null
        },
        { text: leaveDays > 0 ? `Período de afastamento: ${leaveDays} dia(s)` : "Sem afastamento informado", emphasis: null },
        {
          text: manipulationDetected
            ? "Sinais de adulteração detectados no documento"
            : "Sem sinais de adulteração digital",
          emphasis: manipulationDetected ? "danger" : null
        },
      ],
    },
    {
      title: "4. Dados do Médico",
      bullets: [
        {
          text: crmNumber
            ? `CRM ${crmNumber}${crmUF ? `/${crmUF}` : ""}${crmOk ? " verificado e ativo" : " — situação irregular"}`
            : "CRM ausente no documento",
          emphasis: (!crmNumber || !crmOk) ? "danger" : null
        },
        {
          text: crmOk
            ? "Registro regular no Conselho Regional"
            : `Situação do CRM: ${crmSituation || "não verificada"}`,
          emphasis: !crmOk ? "danger" : null
        },
      ],
    },
    {
      title: "5. Qualidade e Apresentação",
      bullets: [
        {
          text: isTrue(get(input, "document_elements.has_letterhead", false))
            ? "Papel timbrado identificado"
            : "Papel timbrado não identificado",
          emphasis: null
        },
        {
          text: anyVisualIssue
            ? "Problemas de qualidade de imagem detectados"
            : "Qualidade de imagem adequada",
          emphasis: anyVisualIssue ? "danger" : null
        },
        {
          text: (imgConsistency >= 0.9 && imgCompleteness >= 0.9 && imgQuality >= 0.9)
            ? "Scores de imagem dentro do esperado"
            : `Scores de imagem abaixo do ideal (consistência: ${imgConsistency}, qualidade: ${imgQuality})`,
          emphasis: (imgConsistency < 0.9 || imgQuality < 0.9) ? "danger" : null
        },
      ],
    },
  ];
}

